import{j as i,b as e,c as l,aa as t}from"./chunks/framework.Bxf40uRC.js";const _=JSON.parse('{"title":"Redis之数据类型","description":"","frontmatter":{},"headers":[],"relativePath":"Redis/Redis之数据类型.md","filePath":"Redis/Redis之数据类型.md","lastUpdated":null}'),a={name:"Redis/Redis之数据类型.md"},s=t('<h1 id="redis之数据类型" tabindex="-1">Redis之数据类型 <a class="header-anchor" href="#redis之数据类型" aria-label="Permalink to &quot;Redis之数据类型&quot;">​</a></h1><h2 id="一、数据类型" tabindex="-1">一、数据类型 <a class="header-anchor" href="#一、数据类型" aria-label="Permalink to &quot;一、数据类型&quot;">​</a></h2><h3 id="_1-string" tabindex="-1">1. String <a class="header-anchor" href="#_1-string" aria-label="Permalink to &quot;1. String&quot;">​</a></h3><h4 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h4><p>String是Redis中最常见的数据存储类型：</p><ul><li>其基本编码方式是<strong>RAW</strong>，基于简单动态字符串(SDS)实现，存储上限为512MB</li><li>如果存储的SDS长度小于44字节，则会采用<strong>EMBSTR</strong> 编码，此时object head与SDS是一段连续空间。申请内存时只需要调用一次内存分配函数，效率更高</li><li>如果存储的字符串是整数值，并且大小在LONG_MAX范围内，则会采用INT编码：直接将数据保存在RedisObject的ptr指针位置（刚好八字节），不再需要SDS了。</li></ul><p><img src="https://s2.loli.net/2023/12/20/6QVjfFLGDcWiHAr.png" alt="image-20231220215008297"></p><h3 id="_2-list" tabindex="-1">2. List <a class="header-anchor" href="#_2-list" aria-label="Permalink to &quot;2. List&quot;">​</a></h3><p>Redis的List类型可以从首、尾操作列表中的元素：</p><p>哪一个数据结构能够满足上述特征？</p><ul><li>LinkedList：普通链表，可以从双端访问，内存占用较高，内存碎片较多</li><li>ZipList：压缩列表，可以从双端访问，内存占用低，存储上限低</li><li><strong>QuickList</strong>：LinkedList + ZipList，可以从双端访问，内存占用较低，包含多个ZipList，存储上限高</li></ul><p><img src="https://s2.loli.net/2023/12/20/KvyICMcHoz6e4Qa.png" alt="image-20231220221049835"></p><h3 id="_3-set" tabindex="-1">3. Set <a class="header-anchor" href="#_3-set" aria-label="Permalink to &quot;3. Set&quot;">​</a></h3><h4 id="定义-1" tabindex="-1">定义 <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;定义&quot;">​</a></h4><p>Set是Redis中的单列集合，满足下列特点：</p><ul><li><p>不保证有序性</p></li><li><p>保证元素唯一(可以判断元素是否存在)</p></li><li><p>求交集、并集、差集</p></li><li><p>为了查询效率和唯一性，set采用HT编码(DIct)。Dict中的Key用来存储元素，value统一为null；</p></li><li><p>当存储的所有数据都是整数，并且元素数量不超过set-max-intset-entries时，Set会采用IntSet编码，以节省内存；</p></li></ul><p><img src="https://s2.loli.net/2023/12/20/EaPb6TN4XYHA1OG.png" alt="image-20231220222420979"></p><h3 id="_4-zset" tabindex="-1">4. ZSet <a class="header-anchor" href="#_4-zset" aria-label="Permalink to &quot;4. ZSet&quot;">​</a></h3><h4 id="定义-2" tabindex="-1">定义 <a class="header-anchor" href="#定义-2" aria-label="Permalink to &quot;定义&quot;">​</a></h4><p>ZSet也就是SortedSet，其中每一个元素都需要指定一个score值和member值：</p><ul><li>可以根据score值排序</li><li>member必须唯一</li><li>可以根据member查询分数</li></ul><h4 id="实现方式1" tabindex="-1">实现方式1 <a class="header-anchor" href="#实现方式1" aria-label="Permalink to &quot;实现方式1&quot;">​</a></h4><p>因此zset底层数据结构必须满足键值存储、键必须唯一、可排序这几个需求。</p><ul><li><strong>SkipList</strong>：可以排序，并且可以同时存储score和ele值(但是无法满足快速查询member)</li><li><strong>HT(Dict)</strong>：可以键值存储，并且可以根据key找value</li><li>全部都要，通过HT进行member查询和唯一性，跳表来进行排序查询</li></ul><p><img src="https://s2.loli.net/2023/12/20/gctAubBrhZD4lzn.png" alt="image-20231220223055955"></p><p><img src="https://s2.loli.net/2023/12/20/aXlnd6D7HW2FgOo.png" alt="image-20231220223211601"></p><h4 id="实现方式2" tabindex="-1">实现方式2 <a class="header-anchor" href="#实现方式2" aria-label="Permalink to &quot;实现方式2&quot;">​</a></h4><p>当元素数量不多时，HT和SkipList优势不明显，而且更耗内存。因此zset还会采用ZipList结构来节省内存，不过需要同时满足两个条件。</p><ul><li>元素数量小于zset_max_ziplist_entries，默认值128</li><li>每个元素都小于zset_max_ziplist_value字节，默认值64</li></ul><p>ziplist本身没有这种功能，而且没有键值对的概念，因此需要zset通过编码实现：</p><ul><li>ZipList是连续内存，因此score和element是紧挨着在一起的两个entry，element在前，socre在后</li><li>score越小越接近队首，socre越大越接近队尾，按照score值升序排列</li><li>查询的时候，直接遍历</li><li>插入的时候，排序插入</li></ul><p><img src="https://s2.loli.net/2023/12/20/zZtbIkTu47xBp3g.png" alt="image-20231220224501142"></p><h4 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h4><ul><li><p>当zset初始化的时候，按照以下规则进行初始化</p><ul><li>检查是否满足ziplist的条件，优先ziplist</li></ul><p><img src="https://s2.loli.net/2023/12/20/Uf894KQLZi2F6dB.png" alt="image-20231220223801659"></p></li><li><p>编码转换部分</p><ul><li>如果是ziplist且具有转换的风险，则进行转换 <ul><li>添加后超过数量</li><li>添加的元素大小超过</li><li>总的超过</li></ul></li></ul><p><img src="https://s2.loli.net/2023/12/20/IvTN2j5ZtW9CMq4.png" alt="image-20231220224131674"></p></li></ul><h3 id="_5-hash" tabindex="-1">5. Hash <a class="header-anchor" href="#_5-hash" aria-label="Permalink to &quot;5. Hash&quot;">​</a></h3><h4 id="定义-3" tabindex="-1">定义 <a class="header-anchor" href="#定义-3" aria-label="Permalink to &quot;定义&quot;">​</a></h4><ul><li>都是键值存储</li><li>都需求根据键获取值</li><li>键必须唯一</li></ul><p>区别如下：</p><ul><li>zset的键是member，值是socre；hash的键和值都是任意值</li><li>zset要根据score排序；hash则无需排序</li></ul><h4 id="实现方式" tabindex="-1">实现方式 <a class="header-anchor" href="#实现方式" aria-label="Permalink to &quot;实现方式&quot;">​</a></h4><p>Hash底层采用的编码与Zset基本一致，只需要把排序有关的SkipList去掉即可：</p><ul><li>Hash结构默认ZipList编码，用以节省内存。ZipList中相邻的两个entry分别保存field和value</li><li>当数据量比较大的时候，Hash会默认采用Dict编码，也就是Dict，触发条件有两个： <ul><li>ZipList中的元素数量超过了hash-max-ziplist-entries(默认512)；</li><li>ZipList中的任意entry大小超过了hash-max-ziplist-value(默认64字节)；</li><li>ZipList中的总的内存大小超过了；</li></ul></li></ul><p><img src="https://s2.loli.net/2023/12/20/iACVjwLrQBglHvY.png" alt="image-20231220225145094"></p>',43),r=[s];function o(n,h,p,d,c,u){return e(),l("div",null,r)}const g=i(a,[["render",o]]);export{_ as __pageData,g as default};
